var e=[{id:`L8_1`,type:`dialog`,speaker:`DOMA_FALLEN_NULL_NULL`,text:{KOREA:`우후후후......`,JPN:`フフフフ……`,ENG:`Hah hah hah...`,TWN:`呵呵呵呵……`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`DOMA_FALLEN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`YUMA_FALLEN_NULL_NULL`,text:{KOREA:`크하하하핫!!!`,JPN:`クハハハハッ！！！`,ENG:`Bwa hah hah hah!`,TWN:`哇哈哈哈哈哈！！`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`YUMA_FALLEN_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`YUMA_FALLEN_NULL_NULL`,text:{KOREA:`빠샤-!`,JPN:`うりゃーっ！`,ENG:`Kapow!`,TWN:`喝啊！`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`YUMA_FALLEN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`YUMA_FALLEN_NULL_NULL`,text:{KOREA:`아, 이제 겨우 흥이 오르던 참인데 벌써 자빠지다니......`,JPN:`ちぇ、やっと盛り上がってきたところなのに、もう倒れちまうのかよ……`,ENG:`No! I was just warming up, and they're already all down.`,TWN:`啊，我才剛興奮起來，結果這麼快就不行了啊……`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`YUMA_FALLEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`YUMA_FALLEN_NULL_NULL`,text:{KOREA:`침식체란 것들은 생존본능이 인간보다 약하다니까?`,JPN:`侵食体ってのは、人間より生存本能がないんだな。`,ENG:`These C.O.s just don't have the will to struggle, like humans.`,TWN:`侵蝕體的生存本能比人類還弱嗎？`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`YUMA_FALLEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`침식체들이 원래 이렇게 약한 존재였나......?`,JPN:`侵食体って元々こんなに弱いものでしたか……？`,ENG:`I didn't know C.O.s were so weak...`,TWN:`還是侵蝕體本來就是弱小的存在……？`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`DOMA_FALLEN_NULL_NULL`,text:{KOREA:`후후, 이런 실례. 동생이 사냥에 너무 심취한 것 같군요.`,JPN:`フフ、これは失礼。妹が狩りに夢中になっていたようです。`,ENG:`Hah hah. My apologies. My little sister may have gotten carried away with hunting.`,TWN:`呵呵，失禮了。我妹妹好像太過投入狩獵了。`},stage:{bg:`SUMMER_BEACH`,slots:{L:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`DOMA_FALLEN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`DOMA_FALLEN_NULL_NULL`,text:{KOREA:`어쨌든 이 정도면 제물은 충분히 모인 것 같네요.`,JPN:`とにかく、供え物は十分揃いましたね。`,ENG:`Anyway, this should be enough for the offerings.`,TWN:`不管怎樣，這樣祭品應該足夠了。`},stage:{bg:`SUMMER_BEACH`,slots:{L:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`DOMA_FALLEN_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L28_1`,type:`dialog`,speaker:`DOMA_FALLEN_NULL_NULL`,text:{KOREA:`그렇죠, 주인님?`,JPN:`そうでしょう、ご主人様？`,ENG:`Isn't that right, Mistress?`,TWN:`您說是吧，主人？`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`DOMA_FALLEN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_SUMMER_NULL`,text:{KOREA:`하암~ 벌써 끝났느냐?`,JPN:`ふああ～もう終わりか？`,ENG:`*Yawn* Are you done already?`,TWN:`哈啊～這麼快就結束了啊？`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_SUMMER_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_SUMMER_NULL`,text:{KOREA:`그럼 이 몸이 나설 차례로군.`,JPN:`それじゃ、妾の出番だな。`,ENG:`Then, it's time for me to step in.`,TWN:`那就輪到我了。`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`저기...... 그런데 정말 이런 게 운명의 상대를 찾는데 도움이 될까요?`,JPN:`あの……ところで、本当にこんなことが運命の相手を探すのに役立つんですか？`,ENG:`Excuse me, but can this really help me find my soul mate?`,TWN:`那個……這樣真的能幫我找到命運之人嗎？`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_SUMMER_NULL`,text:{KOREA:`거 참 음침한 외모만큼이나 믿음이 부족한 처녀로구나.`,JPN:`まったく、陰気な乙女じゃな。`,ENG:`You're as suspicious as you are gloomy.`,TWN:`真是個外表陰沉又多疑的女孩啊。`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_SUMMER_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L33_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_SUMMER_NULL`,text:{KOREA:`도움이 안 되면 뭣 하러 직접 여기까지 나오는 수고를 하겠느냐?`,JPN:`役に立たないというなら、何のために妾が直接出向いたと思っておるのじゃ。`,ENG:`I wouldn't have come all the way here if it didn't help.`,TWN:`如果沒有用，我又何必大老遠地跑來這裡？`},stage:{bg:`SUMMER_BEACH`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_SUMMER_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};